import React, { useMemo, useState } from 'react';
import './MyAppointments.css';

// Utilities to parse and compare dates
const toDate = (dateStr, timeStr) => {
  // dateStr: YYYY-MM-DD, timeStr: e.g., 04:30 PM or 09:00
  if (!dateStr) return null;
  const [hhmm, period] = (timeStr || '00:00').split(' ');
  const [hhRaw, mm] = hhmm.split(':');
  let hh = parseInt(hhRaw, 10);
  if (period) {
    const isPM = period.toUpperCase() === 'PM';
    if (isPM && hh < 12) hh += 12;
    if (!isPM && hh === 12) hh = 0;
  }
  const iso = `${dateStr}T${String(hh).padStart(2, '0')}:${mm || '00'}:00`;
  return new Date(iso);
};

export default function MyAppointments() {
  const [tab, setTab] = useState('upcoming'); // upcoming | past | cancelled

  const allAppointments = useMemo(() => {
    try {
      const raw = localStorage.getItem('helio_appointments');
      const parsed = raw ? JSON.parse(raw) : [];
      // Only accept objects with mandatory fields
      return Array.isArray(parsed)
        ? parsed.filter(a => a && a.id && a.date && a.time)
        : [];
    } catch (e) {
      console.error('Failed to parse appointments from storage:', e);
      return [];
    }
  }, []);

  const now = new Date();
  const [upcoming, past, cancelled] = useMemo(() => {
    const up = [];
    const pa = [];
    const ca = [];
    for (const a of allAppointments) {
      if (a.status === 'cancelled') {
        ca.push(a);
        continue;
      }
      const d = toDate(a.date, a.time);
      if (d && d.getTime() >= now.getTime()) up.push(a); else pa.push(a);
    }
    // Sort upcoming ascending by date, past descending
    up.sort((x, y) => toDate(x.date, x.time) - toDate(y.date, y.time));
    pa.sort((x, y) => toDate(y.date, y.time) - toDate(x.date, x.time));
    return [up, pa, ca];
  }, [allAppointments]);

  const list = tab === 'upcoming' ? upcoming : tab === 'past' ? past : cancelled;

  const renderCard = (a) => (
    <div className="ma-card" key={a.id}>
      <div className="ma-left">
        <div className="ma-avatar">{(a.doctor || 'Dr').split(' ').map(n=>n[0]).slice(0,2).join('')}</div>
      </div>
      <div className="ma-body">
        <h4 className="ma-doctor">{a.doctor || 'Doctor'}</h4>
        <p className="ma-specialty">{a.specialist || ''}</p>
        <div className="ma-meta">
          <div><small className="text-muted">Date:</small><div className="ma-strong">{a.date}</div></div>
          <div><small className="text-muted">Time:</small><div className="ma-strong">{a.time}</div></div>
          <div><small className="text-muted">Hospital:</small><div className="ma-strong">{a.hospitalName || '-'}</div></div>
        </div>
        {a.healthIssue && (
          <div className="ma-notes"><strong>Reason:</strong><div>{a.healthIssue}</div></div>
        )}
        <div className="ma-actions">
          <button className="btn btn-outline" disabled>Reschedule</button>
          <button className="btn btn-outline-danger" disabled>Cancel</button>
        </div>
      </div>
      <div className="ma-right">
        <div className="ma-status">{a.status === 'upcoming' ? 'Scheduled' : (a.status || 'Scheduled')}</div>
      </div>
    </div>
  );

  return (
    <div className="ma-page container mx-auto px-6 py-8">
      <h1 className="text-2xl font-bold mb-4">My Appointments</h1>

      <div className="ma-tabs card mb-6">
        <button className={`ma-tab ${tab==='upcoming'?'active':''}`} onClick={()=>setTab('upcoming')}>Upcoming</button>
        <button className={`ma-tab ${tab==='past'?'active':''}`} onClick={()=>setTab('past')}>Past</button>
        <button className={`ma-tab ${tab==='cancelled'?'active':''}`} onClick={()=>setTab('cancelled')}>Cancelled</button>
      </div>

      <div className="ma-list">
        {list.length > 0 ? (
          list.map(renderCard)
        ) : (
          <div className="text-muted">{tab === 'upcoming' ? 'No upcoming appointments yet.' : tab === 'past' ? 'No past appointments.' : 'No cancelled appointments.'}</div>
        )}
      </div>
    </div>
  );
}
